   375→	function bookmarkPost(button, pid) {
   376→		const method = button.attr('data-bookmarked') === 'false' ? 'put' : 'del';
   377→
   378→		api[method](`/posts/${encodeURIComponent(pid)}/bookmark`, undefined, function (err) {
