   392→	function getUserSlug(button) {
   393→		return new Promise((resolve) => {
   394→			let slug = '';
   395→			if (button.attr('component') === 'topic/reply') {
   396→				resolve(slug);
   397→				return;
   398→			}
   399→			const post = button.parents('[data-pid]');
   400→			if (post.length) {
   401→				require(['slugify'], function (slugify) {
   402→					slug = slugify(post.attr('data-username'), true);
   403→					if (!slug) {
   404→						if (post.attr('data-uid') !== '0') {
   405→							slug = '[[global:former-user]]';
   406→						} else {
   407→							slug = '[[global:guest]]';
