   409→					}
   410→					if (slug && slug !== '[[global:former-user]]' && slug !== '[[global:guest]]') {
   411→						slug = '@' + slug;
   412→					}
   413→					resolve(slug);
   414→				});
   415→				return;
   416→			}
   417→
   418→			resolve(slug);
   419→		});
   420→	}
