   485→				create: {
   486→					label: '[[topic:stale.create]]',
   487→					className: 'btn-primary',
   488→					callback: function () {
   489→						translator.translate(`[[topic:link-back, ${ajaxify.data.title}, ${config.relative_path}/topic/${ajaxify.data.slug}]]`, function (body) {
   490→							hooks.fire('action:composer.topic.new', {
   491→								cid: ajaxify.data.cid,
   492→								body: body,
   493→								fromStaleTopic: true,
   494→							});
   495→						});
   496→					},
   497→				},
   498→			},
   499→		});
   500→
   501→		warning.modal();
