   506→	function handleSelectionTooltip() {
   507→		if (!ajaxify.data.privileges['topics:reply']) {
   508→			return;
   509→		}
   510→
   511→		hooks.onPage('action:posts.loaded', delayedTooltip);
   512→		$(document).off('selectionchange');
   513→		$(document).on('selectionchange', function () {
   514→			const selectionEmpty = window.getSelection().toString() === '';
   515→			if (selectionEmpty) {
   516→				$('[component="selection/tooltip"]').addClass('hidden');
   517→			}
